import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import FlashBar from '../components/FlashBar';

function DonorLayout({ children }) {
  const { auth, flash, logout } = useAuth();

  return (
    <div className="donor-site-shell">
      <header className="donor-site-header">
        <div className="donor-site-header-inner">
          <div>
            <p className="eyebrow">Donor Side Website</p>
            <h1>CareFlow Donor Hub</h1>
            <p className="subtitle">A complete donor journey with identity, availability, requests, and live matching actions.</p>
          </div>

          <div className="donor-site-actions">
            <span className="chip">User: {auth?.user?.username || 'donor'}</span>
            <Link className="nav-link" to="/">Public Site</Link>
            <a className="nav-link" href="http://localhost:8000/docs" target="_blank" rel="noreferrer">API Docs</a>
            <button className="danger" onClick={logout}>Logout</button>
          </div>
        </div>
        <nav className="donor-site-nav">
          <a href="#identity">Identity</a>
          <a href="#status">Availability</a>
          <a href="#matching">Matching</a>
          <a href="#nearby">Nearby Requests</a>
          <a href="#ranked">Top Matches</a>
        </nav>
      </header>

      <main className="donor-site-main">
        <section className="panel full">
          <FlashBar flash={flash} />
        </section>
        {children}
      </main>
    </div>
  );
}

export default DonorLayout;
